---
import { navigation } from '../data/navigation';
import Icon from './Icon.astro';

let isOpen = false;
---

<header class="fixed top-0 left-0 right-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200 transition-all duration-300">
  <div class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
    <div class="flex items-center justify-between h-20">
      <!-- Logo -->
      <a href="/" class="flex items-center gap-2 group">
        <div class="w-10 h-10 bg-gradient-to-br from-blue-600 to-purple-600 rounded-xl flex items-center justify-center text-white transform transition-transform group-hover:scale-110 duration-300">
          <Icon name="logo" size={24} />
        </div>
        <span class="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-900 to-slate-700">
          Kanviz
        </span>
      </a>

      <!-- Desktop Navigation -->
      <nav class="hidden md:flex items-center gap-8">
        {navigation.links.map((link) => (
          <a
            key={link.href}
            href={link.href}
            class="text-slate-600 hover:text-blue-600 font-medium transition-colors duration-200 relative group"
          >
            {link.name}
            <span class="absolute -bottom-1 left-0 w-0 h-0.5 bg-blue-600 transition-all duration-300 group-hover:w-full"></span>
          </a>
        ))}
        <a
          href="/contact"
          class="px-6 py-2.5 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-lg font-medium hover:shadow-lg hover:shadow-blue-500/30 transform hover:-translate-y-0.5 transition-all duration-300"
        >
          Get Started
        </a>
      </nav>

      <!-- Mobile Menu Button -->
      <button
        class="md:hidden p-2 text-slate-600 hover:text-blue-600 transition-colors"
        onclick={() => (isOpen = !isOpen)}
        aria-label="Toggle menu"
      >
        <Icon name={isOpen ? 'x' : 'menu'} size={24} />
      </button>
    </div>
  </div>

  <!-- Mobile Navigation -->
  {isOpen && (
    <div class="md:hidden absolute top-20 left-0 right-0 bg-white border-b border-slate-200 shadow-xl animate-fade-in">
      <nav class="flex flex-col p-4 gap-4">
        {navigation.links.map((link) => (
          <a
            key={link.href}
            href={link.href}
            onclick={() => (isOpen = false)}
            class="px-4 py-3 text-slate-600 hover:text-blue-600 hover:bg-slate-50 rounded-lg font-medium transition-colors"
          >
            {link.name}
          </a>
        ))}
        <a
          href="/contact"
          onclick={() => (isOpen = false)}
          class="px-4 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-lg font-medium text-center"
        >
          Get Started
        </a>
      </nav>
    </div>
  )}
</header>

<style>
  @keyframes fade-in {
    from {
      opacity: 0;
      transform: translateY(-10px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }
  .animate-fade-in {
    animation: fade-in 0.3s ease-out forwards;
  }
</style>

