  id?: string;
  class?: string;
  bg?: 'light' | 'dark' | 'gradient';
  padding?: 'none' | 'sm' | 'md' | 'lg';
}

const {
  id,
  class: className,
  bg = 'light',
  padding = 'lg'
} = defineProps<Props>();
---

<section
  id={id}
  class={{
    [className || '']: !!className,
    'bg-slate-50': bg === 'light',
