---
import Layout from '../layouts/Layout.astro';
import { hero } from '../data/hero';
import { services } from '../data/services';
import { team } from '../data/team';
import Section from '../components/Section.astro';
import Card from '../components/Card.astro';
import Icon from '../components/Icon.astro';

const stats = [
  { label: 'Clients Served', value: '500+' },
  { label: 'Projects Completed', value: '1,200+' },
  { label: 'Team Members', value: '25+' },
  { label: 'Years Experience', value: '15+' },
];
---

<Layout title="Home" description="Transform your business with data-driven insights through our visualization solutions and strategic consulting.">
  {/* Hero Section */}
  <Section bg="gradient" padding="lg" class="relative overflow-hidden">
    <div class="absolute inset-0 opacity-10">
      <div class="absolute top-0 left-0 w-full h-full bg-[radial-gradient(#fff_1px,transparent_1px)] [background-size:24px_24px]"></div>
    </div>

    <div class="relative grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
      <div class="space-y-8 animate-fade-in-up">
        <div class="inline-flex items-center gap-2 px-4 py-2 bg-white/20 backdrop-blur-sm rounded-full text-white text-sm font-medium border border-white/30">
          <span class="flex h-2 w-2 rounded-full bg-green-400 animate-pulse"></span>
          Accepting new projects for Q3 2026
        </div>

        <h1 class="text-5xl md:text-6xl lg:text-7xl font-extrabold leading-tight text-white">
          Transform Your <br />
          <span class="bg-clip-text text-transparent bg-gradient-to-r from-cyan-300 to-blue-300">Business Data</span> Into Action
        </h1>

        <p class="text-lg md:text-xl text-slate-200 max-w-xl leading-relaxed">
          We help companies turn complex data into actionable insights through innovative visualization solutions and strategic consulting that drive real growth.
        </p>

        <div class="flex flex-col sm:flex-row gap-4">
          <a href="/contact" class="px-8 py-4 bg-white text-blue-900 rounded-xl font-bold text-lg hover:bg-slate-50 transition-colors duration-300 flex items-center justify-center gap-2 shadow-lg shadow-blue-900/20">
            Get Started
            <Icon name="arrow-right" size={20} />
          </a>
          <a href="/services" class="px-8 py-4 bg-transparent border-2 border-white text-white rounded-xl font-bold text-lg hover:bg-white/10 transition-colors duration-300 flex items-center justify-center">
            Our Services
          </a>
        </div>
      </div>

      <div class="relative animate-fade-in-right">
        <div class="absolute -inset-4 bg-gradient-to-r from-blue-500 to-purple-600 rounded-3xl opacity-30 blur-2xl"></div>
        <div class="relative bg-white/10 backdrop-blur-lg border border-white/20 rounded-3xl p-8 shadow-2xl">
          <div class="grid grid-cols-2 gap-6">
            {stats.map((stat, index) => (
              <div key={index} class="text-center space-y-2">
                <div class="text-4xl md:text-5xl font-bold text-white">{stat.value}</div>
                <div class="text-sm md:text-base text-slate-300">{stat.label}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  </Section>

  {/* Services Section */}
  <Section bg="light" padding="lg">
    <div class="text-center max-w-2xl mx-auto mb-16 space-y-4">
      <h2 class="text-3xl md:text-4xl font-bold text-slate-900">Our Services</h2>
      <p class="text-lg text-slate-600">Comprehensive solutions designed to help you leverage data effectively</p>
    </div>

    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
      {services.map((service) => (
        <Card key={service.id} class="p-6 space-y-4 group">
          <div class={`w-14 h-14 rounded-xl bg-gradient-to-br ${service.color} flex items-center justify-center text-white mb-2 group-hover:scale-110 transition-transform duration-300`}>
            <Icon name={service.icon} size={28} />
          </div>
          <h3 class="text-xl font-bold text-slate-900">{service.title}</h3>
          <p class="text-slate-600 leading-relaxed">{service.description}</p>
          <a href="/services" class="inline-flex items-center gap-1 text-blue-600 font-medium hover:gap-2 transition-all">
            Learn more <Icon name="chevron-right" size={16} />
          </a>
        </Card>
      ))}
    </div>
  </Section>

  {/* About Section */}
  <Section bg="dark" padding="lg">
    <div class="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
      <div class="relative order-2 lg:order-1">
        <div class="absolute -inset-4 bg-gradient-to-r from-purple-600 to-pink-600 rounded-3xl opacity-20 blur-2xl"></div>
        <div class="relative bg-slate-800 rounded-3xl overflow-hidden shadow-2xl">
          <img src="https://images.unsplash.com/photo-1552664730-d38731e74c12?auto=format&fit=crop&w=800&q=80" alt="Team working together" class="w-full h-full object-cover" />
        </div>
      </div>

      <div class="order-1 lg:order-2 space-y-6">
        <h2 class="text-3xl md:text-4xl font-bold text-white">Who We Are</h2>
        <p class="text-lg text-slate-300 leading-relaxed">
          Kanviz is a premier data visualization and business intelligence company dedicated to helping organizations unlock the full potential of their data. Founded in 2010, we've grown from a small team of data enthusiasts to a leading provider of analytics solutions.
        </p>
        <p class="text-lg text-slate-300 leading-relaxed">
          Our mission is simple: make data accessible, actionable, and impactful for businesses of all sizes. We believe that great data visualization isn't just about pretty charts—it's about telling compelling stories that drive better decisions.
        </p>

        <div class="grid grid-cols-2 gap-6 pt-4">
          {[
            { label: 'Data Experts', value: '100%' },
            { label: 'Client Satisfaction', value: '98%' },
            { label: 'On-Time Delivery', value: '99%' },
            { label: 'Industry Experience', value: '15+' },
          ].map((item, index) => (
            <div key={index} class="space-y-1">
              <div class="text-2xl font-bold text-white">{item.value}</div>
              <div class="text-sm text-slate-400">{item.label}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  </Section>

  {/* Team Section */}
  <Section bg="light" padding="lg">
    <div class="text-center max-w-2xl mx-auto mb-16 space-y-4">
      <h2 class="text-3xl md:text-4xl font-bold text-slate-900">Meet Our Team</h2>
      <p class="text-lg text-slate-600">The talented people behind our success</p>
    </div>

    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
      {team.map((member) => (
        <Card key={member.id} class="text-center p-6 space-y-4 group">
          <div class="w-24 h-24 mx-auto rounded-full bg-gradient-to-br from-slate-200 to-slate-300 overflow-hidden border-4 border-white shadow-lg group-hover:border-blue-500 transition-colors duration-300">
            <img src={`https://ui-avatars.com/api/?name=${encodeURIComponent(member.name)}&background=random`} alt={member.name} class="w-full h-full object-cover" />
          </div>
          <div>
            <h3 class="text-lg font-bold text-slate-900">{member.name}</h3>
            <p class="text-blue-600 font-medium">{member.role}</p>
          </div>
          <p class="text-slate-600 text-sm leading-relaxed">{member.bio}</p>
          {member.socials && (
            <div class="flex justify-center gap-3 pt-2">
              {member.socials.linkedin && (
                <a href={member.socials.linkedin} class="text-slate-400 hover:text-blue-600 transition-colors">
                  <Icon name="linkedin" size={20} />
                </a>
              )}
              {member.socials.twitter && (
                <a href={member.socials.twitter} class="text-slate-400 hover:text-blue-600 transition-colors">
                  <Icon name="twitter" size={20} />
                </a>
              )}
              {member.socials.github && (
                <a href={member.socials.github} class="text-slate-400 hover:text-slate-800 transition-colors">
                  <Icon name="github" size={20} />
                </a>
              )}
            </div>
          )}
        </Card>
      ))}
    </div>
  </Section>

  {/* CTA Section */}
  <Section bg="gradient" padding="lg">
    <div class="text-center max-w-3xl mx-auto space-y-8">
      <h2 class="text-4xl md:text-5xl font-bold text-white">Ready to Transform Your Business?</h2>
      <p class="text-xl text-slate-200 leading-relaxed">
        Let's discuss how Kanviz can help you unlock the power of your data with custom visualization solutions tailored to your needs.
      </p>
      <div class="flex flex-col sm:flex-row gap-4 justify-center">
        <a href="/contact" class="px-8 py-4 bg-white text-blue-900 rounded-xl font-bold text-lg hover:bg-slate-50 transition-colors duration-300 shadow-lg shadow-blue-900/20">
          Schedule a Consultation
        </a>
      </div>
    </div>
  </Section>
</Layout>

<style>
  @keyframes fade-in-up {
    from {
      opacity: 0;
      transform: translateY(20px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }
  .animate-fade-in-up {
    animation: fade-in-up 0.6s ease-out forwards;
  }

  @keyframes fade-in-right {
    from {
      opacity: 0;
      transform: translateX(20px);
    }
    to {
      opacity: 1;
      transform: translateX(0);
    }
  }
  .animate-fade-in-right {
    animation: fade-in-right 0.6s ease-out forwards;
  }
</style>

